def does_database_exist(self, database_name):
    """
    Check if a database with the given name exists.

    Raises:
        AirflowBadRequest: If the database_name is None or empty.
    """
    if not database_name:
        raise AirflowBadRequest("Database name cannot be None or empty.")

    existing_database = list(self.get_conn().QueryDatabases({
        "query": "SELECT * FROM r WHERE r.id=@id",
        "parameters": [
            {"name": "@id", "value": database_name}
        ]
    }))

    return len(existing_database) > 0
